## 任务1：修复 BackgroundCheckReminderDialog.vue 中的混选 bug 并支持 not_resigned 存记录

文件：src/apps/CenterContentArea/CandidatePanelsNew/BackgroundCheckReminderDialog.vue

**改动目标**：修改 `handleConfirm` 方法逻辑：
- 对每个段，不管选了什么，都调用 `background-check-record-skip` API（包括 `not_resigned_yet`，对应后端的 `not_resigned`）
- 只要有任意段选了 `not_resigned_yet`，最终 emit `handled({ defer: true })`；否则 emit `handled({ defer: false })`
- 去掉原来的 `allNotResigned` 全量判断逻辑

当前 handleConfirm 方法：
```js
async handleConfirm() {
    const hasNoNeed = Object.values(this.choices).some(c => c === 'no_need')
    if (hasNoNeed) {
        const missing = this.segments
            .filter(s => this.choices[s.work_experience_index] === 'no_need' && !(this.specificReasons[s.work_experience_index] || '').trim())
        if (missing.length) {
            showMessageWarning(this.$t('p250304_07'))
            return
        }
    }

    const allNotResigned = this.segments.length > 0 && this.segments.every(s => this.choices[s.work_experience_index] === 'not_resigned_yet')
    if (allNotResigned) {
        this.$emit('handled', { defer: true })
        this.$emit('update:visible', false)
        return
    }

    this.panelLoading = true
    try {
        for (const seg of this.segments) {
            const choice = this.choices[seg.work_experience_index]
            if (choice === 'offline' || choice === 'no_need') {
                await axios2(`${ajaxUrl.WEB_API_URL}recruitment-procession/background-check-record-skip`, 'post', {
                    rec_pro_id: this.recProId,
                    work_experience_index: seg.work_experience_index,
                    skip_reason: choice,
                    skip_specific_reason: choice === 'no_need' ? (this.specificReasons[seg.work_experience_index] || '').trim() : undefined,
                    encrypt_config: {
                        res_type: 'resume',
                        obj: '$this',
                        non_encrypt_columns: ['sys_lang', 'version_info', 'rec_pro_id', 'work_experience_index', 'skip_reason', 'skip_specific_reason'],
                    },
                })
            }
        }
        this.$emit('handled', { defer: false })
        this.$emit('update:visible', false)
    } catch (e) {
        this.$message.error(e?.error_msg || e?.message || '操作失败')
    } finally {
        this.panelLoading = false
    }
},
```

改为：
```js
async handleConfirm() {
    const hasNoNeed = Object.values(this.choices).some(c => c === 'no_need')
    if (hasNoNeed) {
        const missing = this.segments
            .filter(s => this.choices[s.work_experience_index] === 'no_need' && !(this.specificReasons[s.work_experience_index] || '').trim())
        if (missing.length) {
            showMessageWarning(this.$t('p250304_07'))
            return
        }
    }

    this.panelLoading = true
    try {
        for (const seg of this.segments) {
            const choice = this.choices[seg.work_experience_index]
            const skipReason = choice === 'not_resigned_yet' ? 'not_resigned' : choice
            await axios2(`${ajaxUrl.WEB_API_URL}recruitment-procession/background-check-record-skip`, 'post', {
                rec_pro_id: this.recProId,
                work_experience_index: seg.work_experience_index,
                skip_reason: skipReason,
                skip_specific_reason: choice === 'no_need' ? (this.specificReasons[seg.work_experience_index] || '').trim() : undefined,
                encrypt_config: {
                    res_type: 'resume',
                    obj: '$this',
                    non_encrypt_columns: ['sys_lang', 'version_info', 'rec_pro_id', 'work_experience_index', 'skip_reason', 'skip_specific_reason'],
                },
            })
        }
        const hasDeferred = this.segments.some(s => this.choices[s.work_experience_index] === 'not_resigned_yet')
        this.$emit('handled', { defer: hasDeferred })
        this.$emit('update:visible', false)
    } catch (e) {
        this.$message.error(e?.error_msg || e?.message || '操作失败')
    } finally {
        this.panelLoading = false
    }
},
```

## 任务2：加入已入职时 deferred 段显示不同文案

文件：src/apps/CenterContentArea/CandidatePanelsNew/BackgroundCheckReminderDialog.vue

在 `<div class="segment-block">` 内，当前只有 `segment-title` 和 `segment-options`。

在 `segment-title` 下方、`segment-options` 上方，新增一行提示文案（仅当 segment_type === 'deferred' 时显示）：

找到：
```html
<div class="segment-title">
    {{ $t('p250304_03', { n: seg.work_experience_index, company: seg.company || '-' }) }}
</div>
<el-radio-group v-model="choices[seg.work_experience_index]" class="segment-options">
```

改为：
```html
<div class="segment-title">
    {{ $t('p250304_03', { n: seg.work_experience_index, company: seg.company || '-' }) }}
</div>
<div v-if="seg.segment_type === 'deferred'" class="segment-deferred-tip">
    {{ $t('p250304_08') }}
</div>
<el-radio-group v-model="choices[seg.work_experience_index]" class="segment-options">
```

并在 `<style>` 中新增样式：
```less
.segment-deferred-tip {
    margin-bottom: 8px;
    color: #e6a23c;
    font-size: 13px;
}
```

